import { useEffect, useState } from "react";
import { MonthlyStats } from "../types/dashboard.types";
import { useApiError } from "@/hooks/useApiError";
import {
  getApplicationsMonthlyStats,
} from "../services/dashboard.service";

export function useDashboardMonthlyStats() {
  const { handleError, error, clearError } = useApiError();
  const [departmentsMonthlyStats, setDepartmentsMonthlyStats] =
    useState<MonthlyStats | null>(null);
  const [jobsMonthlyStats, setJobsMonthlyStats] = useState<MonthlyStats | null>(
    null,
  );
  const [applicationsMonthlyStats, setApplicationsMonthlyStats] =
    useState<MonthlyStats | null>(null);
  const [loading, setLoading] = useState(false);

  async function fetchDepartmentsMonthlyStats() {
    clearError();
    try {
      const { data } = await getDepartmentsMonthlyStats();
      setDepartmentsMonthlyStats(data);
    } catch (err) {
      handleError(err);
    }
  }

  async function fetchJobsMonthlyStats() {
    clearError();
    try {
      const { data } = await getJobsMonthlyStats();
      setJobsMonthlyStats(data);
    } catch (err) {
      handleError(err);
    }
  }

  async function fetchApplicationsMonthlyStats() {
    clearError();
    try {
      const { data } = await getApplicationsMonthlyStats();
      setApplicationsMonthlyStats(data);
    } catch (err) {
      handleError(err);
    }
  }

  useEffect(() => {
    setLoading(true);
    Promise.all([
      fetchDepartmentsMonthlyStats(),
      fetchJobsMonthlyStats(),
      fetchApplicationsMonthlyStats(),
    ]).finally(() => setLoading(false));
  }, []);

  return {
    departmentsMonthlyStats,
    jobsMonthlyStats,
    applicationsMonthlyStats,
    loading,

    error,
    clearError,
  };
}
